  {
    "type": "callout",
    "style": "info",
    "body": "If this command prints a version number, Git is installed. If not, visit https://git-scm.com to download it."
  },
  {
    "type": "quiz",
    "variant": "multiple-choice",
    "question": "What does Git track?",
    "options": [
      "CPU usage over time",
      "Changes to files over time",
      "Internet bandwidth",
      "Battery life"
    ],
    "answer": 1,
    "explanation": "Git is a version control system. Its core purpose is tracking changes to files so you can review history, revert mistakes, and collaborate with others."
  }
]

[
  {
    "type": "text",
    "content": "A **commit** is a snapshot of your project at a specific point in time. Every commit has a unique identifier, a message describing what changed, and a pointer to the previous commit.\n\nThe basic workflow is: make changes, **stage** the files you want to include, and then **commit** them with a message."
  },
  {
    "type": "code",
    "language": "bash",
    "content": "git add index.html\ngit commit -m \"Add homepage\"",
    "label": "Stage and commit a file"
  },
  {
    "type": "callout",
    "style": "tip",
    "body": "Write commit messages in the imperative mood: \"Add homepage\" rather than \"Added homepage\". This matches the convention used by Git itself."
  },
  {
    "type": "quiz",
    "variant": "multiple-choice",
    "question": "Which command stages a file for the next commit?",
    "options": [
      "git commit",
      "git push",
      "git add",
      "git status"
    ],
    "answer": 2,
    "explanation": "git add moves changes into the staging area. git commit then records everything in the staging area as a new snapshot."
  }
]
